-- Publish EN Business Immigration series (EP01 ~ EP04)
-- Generated by scripts/generate-en-series-sql.js
-- Safe to re-run: ON CONFLICT (slug) upserts; d10/f2r statements are idempotent.
-- Paste this entire file into Supabase → SQL Editor → Run.

-- 1. Ensure the 'template' column exists (idempotent).
ALTER TABLE public.blog_posts
  ADD COLUMN IF NOT EXISTS template TEXT NOT NULL DEFAULT 'toss';

-- 2. Ensure the 'slug' column is UNIQUE so ON CONFLICT below works.
--    (idempotent — skips if already present)
DO $migrate$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM pg_constraint
    WHERE conrelid = 'public.blog_posts'::regclass
      AND conname  = 'blog_posts_slug_unique'
  ) THEN
    -- Remove any accidental duplicates first, keeping the most recent row.
    DELETE FROM public.blog_posts a USING public.blog_posts b
    WHERE a.slug = b.slug AND a.created_at < b.created_at;
    ALTER TABLE public.blog_posts
      ADD CONSTRAINT blog_posts_slug_unique UNIQUE (slug);
  END IF;
END
$migrate$;

-- 3. Ensure the existing d10 / f2r posts stay published+toss
--    (recovers them if anything earlier flipped the flag).
UPDATE public.blog_posts
SET is_published = TRUE, template = 'toss'
WHERE slug = 'd10-visa-korea-new-graduate-points-exemption-guide-2026';

UPDATE public.blog_posts
SET is_published = TRUE, template = 'toss'
WHERE slug = 'f2r-visa-korea-regional-university-graduate-residence-guide-2026';


-- ─────────────────────────────────────────────────────────────────
-- EP01 · How to Start a Business in Korea as a Foreigner — The 2026 Guide
-- ─────────────────────────────────────────────────────────────────
INSERT INTO public.blog_posts (
  title, slug, category, excerpt, meta_description, thumbnail_url,
  is_published, template, related_services, content, created_at, updated_at
) VALUES (
  $$How to Start a Business in Korea as a Foreigner — The 2026 Guide$$,
  'start-a-business-in-korea-as-a-foreigner-2026',
  'business',
  $$This is the first installment of our series for foreign nationals considering Business Immigration to Korea. How visa rules apply in practice is covered in Episode 2, the full relocation and launch timeline in Episode 3, and life after settlement in Episode 4.$$,
  $$This is the first installment of our series for foreign nationals considering Business Immigration to Korea. How visa rules apply in practice is covered in Episode 2, the full relocation and launch timeline in Episode 3, and life after settlement in Episode 4.$$,
  NULL,
  TRUE,
  'navy_v4',
  '[]',
  $${"category":"business","categoryLabel":"Business & Investment","episodeNo":"01","rev":"01","seriesNav":[{"no":"01","label":"Visa Overview · Franchise","active":true},{"no":"02","label":"Visa System Structure"},{"no":"03","label":"Relocation & Launch Flow"},{"no":"04","label":"After Business Immigration"}],"title":"How to Start a Business in Korea as a Foreigner — The 2026 Guide","url":"start-a-business-in-korea-as-a-foreigner-2026","disclaimer":"This is the first installment of our series for foreign nationals considering Business Immigration to Korea. How visa rules apply in practice is covered in Episode 2, the full relocation and launch timeline in Episode 3, and life after settlement in Episode 4.","series":"Episode 1 · Business Immigration Series","publishedAt":"2026.04.10","updatedAt":"2026.04.23","readingMin":9,"sections":[{"id":"s1","heading":"The Korean business visa is not only D-8","blocks":[{"type":"p","text":"For foreign nationals looking to do business in Korea, the first visa category they usually encounter is the <b>D-8 visa</b>. Overseas immigration consultancies, the Korean government's English-language materials, and most press coverage all introduce D-8 as Korea's \"business visa.\" As a result, many applicants assume that a D-8 is required to start any business in Korea."},{"type":"p","text":"In practice, however, D-8 is designed for <b>foreign nationals who establish a corporation or invest in an existing one</b>. Its subcategories make this clear: D-8-1 for essential specialists (such as executives) of a foreign-invested corporation, D-8-2 for founders of venture companies, D-8-3 for joint venture partners with a Korean national, and D-8-4 for technology-based startup founders. All of them presuppose a <b>corporation or investment-backed enterprise</b>. The applicant sets up or joins a corporate entity and resides in Korea as its representative or officer."},{"type":"p","text":"But most people considering Business Immigration are not planning a corporate-level venture or a tech startup. They are planning <b>sole-proprietor small businesses</b>: convenience stores, cafés, unmanned retail shops, Korean restaurants, hair salons, laundromats. For this kind of relocation, D-8 is not the right visa — a different category applies."}]},{"id":"s2","heading":"D-9-4 and D-9-5 — visas designed for foreign sole proprietors","blocks":[{"type":"p","text":"Korea maintains a separate visa track for <b>foreign sole proprietors</b>: <b>D-9-4</b> and <b>D-9-5</b>."},{"type":"table","title":"D-9-4 · D-9-5 at a Glance","headers":["Visa","Eligible Applicant","Minimum Investment"],"rows":[["D-9-4","A foreign national who remits funds from abroad, registers as a sole proprietor in their own name, and personally operates the business","300 million KRW or more"],["D-9-5","A former international student holding a Korean master's degree or higher — or a bachelor's degree plus 30+ OASIS points (a point-based startup eligibility screening) — launching a business in Korea","100 million KRW or more"]],"note":"Both visas are open to all nationalities and impose virtually no industry restrictions."},{"type":"p","text":"<b>D-9-4</b> does not involve setting up a corporation. The applicant registers a business under their own name as a sole proprietor. Nationality is unrestricted, and the range of eligible industries is extremely broad."},{"type":"p","text":"<b>D-9-5</b> is a special-track visa for <b>former international students who graduated from a Korean university</b>. It allows those who completed their studies in Korea to continue in Korea as entrepreneurs rather than return home, with a substantially lower investment threshold."},{"type":"callout","text":"Although both visas directly correspond to sole-proprietor small business immigration, <b>these categories are almost entirely absent from the Korea sections of overseas immigration consultancy materials</b>. Because D-8 has become the default reference point for \"Korean business visas,\" many applicants either give up on Business Immigration to Korea altogether or pursue an ill-fitting D-8 path — simply unaware that the sole-proprietor route exists."},{"type":"p","text":"<b>Lawyeon Visa & Immigration Center specializes in D-9-4 and D-9-5 — the sole-proprietor Business Immigration track for foreign nationals.</b> We integrate the regulatory, contractual, and operational aspects of Korean sole-proprietor immigration into a single project, and this is our dedicated practice area."}]},{"id":"s3","heading":"Korea's small-business support programs do not distinguish between Koreans and foreigners","blocks":[{"type":"p","text":"When discussing the sole-proprietor track, another essential point is Korea's <b>small-business support ecosystem</b>."},{"type":"p","text":"The Korean government operates a range of programs for small business owners, including low-interest policy loans, guarantee-backed financing, business stabilization grants, and emergency assistance funds. These programs are administered by the <b>Korea Small Enterprise and Market Service (SEMAS)</b>, under the Framework Act on Small Enterprises. <b>Nationality is not a distinguishing factor: any sole proprietor that meets the statutory small-enterprise criteria — such as the employee-count threshold — is eligible on the same terms, whether Korean or foreign.</b> A foreign national who has completed sole-proprietor business registration becomes eligible for the same support, on the same conditions, as a Korean small business owner."},{"type":"callout","text":"This fact is rarely communicated to foreign nationals considering Business Immigration to Korea. From an overseas perspective, the instinctive question is: \"Can a foreigner really access local government support?\" In Korea, however, the legal framework itself does not separate foreign and domestic sole proprietors — both are included within the same \"small enterprise\" category. In other words, once settled, a foreign operator gains access to public resources that would typically be unavailable to them in their home country."}]},{"id":"s4","heading":"Building a business from scratch is not realistic for a newcomer","blocks":[{"type":"p","text":"Once D-9-4 or D-9-5 is on the table and the idea of relocating to Korea as a sole proprietor becomes concrete, the next question is naturally: \"What business, and how?\""},{"type":"p","text":"From the perspective of someone moving to Korea, the Korean market is unfamiliar territory. The dynamics of commercial districts, consumer behavior, raw-material supply chains, distribution practices, licensing procedures, and labor management conventions all differ from those at home. The Korean-language information environment compounds the difficulty. Selecting an industry, picking a location, securing suppliers, arranging interior construction, hiring staff, and designing marketing — doing all of this from abroad, the same way one might in a familiar home market, is simply not feasible. What makes it more demanding still: <b>all of these decisions must be made before relocating, because the visa cannot be issued without a registered business and a signed commercial lease</b>."},{"type":"p","text":"Given these constraints, the realistic option for a foreign applicant is to enter a business model that is <b>already structured</b>. One where operational playbooks are standardized, supply chains and ordering systems are centralized at the headquarters level, and location selection and interior design follow an established template. A business, in short, that fits the profile of a <b>franchise</b>."}]},{"id":"s-cta-mid","type":"midCta","blocks":[]},{"id":"s5","heading":"Why Korean franchise businesses fit Business Immigration","blocks":[{"type":"p","text":"Among the major markets worldwide, the Korean franchise sector is one of the most highly standardized in terms of business structure."},{"type":"numbered","label":"TYPE","items":[{"n":1,"title":"Convenience stores — headquarters infrastructure compensates for language and market-knowledge gaps","text":"Four headquarters — GS25, CU, 7-Eleven, and Emart24 — account for the majority of the Korean market. All four operate at a similar level of sophistication: standardized operating manuals, integrated ordering systems, consolidated POS data analytics, and regular in-person visits from regional supervisors. A foreign store owner simply plugs into this infrastructure and uses it as-is."},{"n":2,"title":"Unmanned stores — minimal Korean-language face-time required","text":"Unmanned ice cream discount stores, self-service photo studios, unmanned cafés, unmanned meal-kit shops, and the like are operated through kiosks, CCTV, and remote monitoring systems. Physical presence of the owner at the store is not required for day-to-day operation."},{"n":3,"title":"F&B franchises — viable where the operator has prior Korean residency experience","text":"Korean, snack-bar (bunsik), chicken, and café franchises involve more face-to-face customer contact, but much of the operation — menu development, ingredient supply, promotional activity — is handled centrally by the headquarters. Suitable for applicants with prior residency in Korea or a certain level of Korean-language ability."}]},{"type":"callout","text":"The fundamental reason franchises suit Business Immigration is <b>predictability</b>. The hardest part for a foreign applicant deciding on a Korean business from abroad is gauging \"how this business actually runs day-to-day.\" With franchises, that information is structured and made available at the headquarters level in advance."}]},{"id":"s6","heading":"The Franchise Disclosure Document — predictability backed by law","blocks":[{"type":"p","text":"The Korean franchise market is not just voluntarily standardized. <b>Korean law requires franchise headquarters to disclose the actual state of their business to prospective franchisees.</b> The governing statute is the <b>Fair Transactions in Franchise Business Act</b>, and the central mechanism is the <b>Franchise Disclosure Document (정보공개서)</b>."},{"type":"p","text":"The disclosure document is filed with and published on the Korea Fair Trade Commission's official portal, and the headquarters is legally obligated to <b>provide it to a prospective franchisee at least 14 days before contract signing</b>."},{"type":"p","text":"The content of the disclosure document is of a different character from marketing brochures. It breaks down <b>costs by category</b> — licensing, training, interior construction — and discloses the headquarters' financial status, any legal violations by its executives, <b>average revenue per franchise store</b>, opening rates, <b>closure rates</b>, and the number of dispute-mediation cases between headquarters and franchisees. <b>It is a legally mandated disclosure — meaning even unfavorable figures must be published.</b>"},{"type":"p","text":"This framework effectively closes the information asymmetry between a franchise headquarters and a prospective franchisee by law. For a foreign applicant, the mechanism is especially valuable: marketing brochures alone make it hard to assess a headquarters' true condition, but the standardized disclosure fields allow multiple headquarters to be compared on a like-for-like basis. In our project design phase, we apply an internal screening model to exclude headquarters with unstable financials or abnormally high closure rates, and we analyze the disclosure document with the client together."}]},{"id":"closing","heading":"What the next episodes cover","blocks":[{"type":"p","text":"This concludes the overview of Korean Business Immigration visas and the reasons franchise businesses are a practical route along that path. From the next episode onward, we move into what is actually required to prepare."},{"type":"numbered","label":"EPISODE","items":[{"n":2,"title":"Episode 2 — Structure of the Visa System","text":"How investment funds must be deployed to be recognized; for those already residing in Korea, the structure of status-of-stay changes, period-of-stay extensions, and accompanying-family invitations"},{"n":3,"title":"Episode 3 — The Relocation & Launch Flow","text":"The five-stage progression from industry selection through store opening — from the first pre-consultation back home to the day the doors open in Korea"},{"n":4,"title":"Episode 4 — After Business Immigration","text":"Long-term residency, family settlement, real estate, social insurance — the starting point of the long arc that follows visa issuance"}]},{"type":"p","text":"Lawyeon Visa & Immigration Center brings together experienced attorneys from Law Firm Lawyeon, interpreter-coordinators, and startup immigration specialists to support foreign sole-proprietor Business Immigration via D-9-4 and D-9-5. Initial consultations are free of charge, and applicants can submit inquiries directly from their home country through our consultation thread."}]}],"related":[{"tag":"EP 2","title":"Korea Business Visa in 2026 — How Much to Invest, How Long You Can Stay, and Bringing Your Family","url":"korea-business-visa-investment-and-family-guide-2026"},{"tag":"EP 3","title":"How to Open a Store in Korea as a Foreigner — The Step-by-Step 2026 Process","url":"how-to-open-a-store-in-korea-as-a-foreigner-2026"},{"tag":"EP 4","title":"How to Stay in Korea Long-Term as a Foreign Business Owner — Residency, Family, Real Estate, Healthcare (2026)","url":"how-to-stay-in-korea-long-term-as-a-business-owner-2026"}]}$$,
  NOW(),
  NOW()
)
