-- ─────────────────────────────────────────────────────────────────
-- EP02 · Korea Business Visa in 2026 — How Much to Invest, How Long You Can Sta
-- ─────────────────────────────────────────────────────────────────
INSERT INTO public.blog_posts (
  title, slug, category, excerpt, meta_description, thumbnail_url,
  is_published, template, related_services, content, created_at, updated_at
) VALUES (
  $$Korea Business Visa in 2026 — How Much to Invest, How Long You Can Stay, and Bringing Your Family$$,
  'korea-business-visa-investment-and-family-guide-2026',
  'business',
  $$This installment covers how the D-9-4 and D-9-5 visas introduced in Episode 1 are actually applied in practice. The full relocation timeline is addressed in Episode 3, and life after settlement in Episode 4.$$,
  $$This installment covers how the D-9-4 and D-9-5 visas introduced in Episode 1 are actually applied in practice. The full relocation timeline is addressed in Episode 3, and life after settlement in Episode 4.$$,
  NULL,
  TRUE,
  'navy_v4',
  '[]',
  $${"category":"business","categoryLabel":"Business & Investment","episodeNo":"02","rev":"01","seriesNav":[{"no":"01","label":"Visa Overview · Franchise"},{"no":"02","label":"Visa System Structure","active":true},{"no":"03","label":"Relocation & Launch Flow"},{"no":"04","label":"After Business Immigration"}],"title":"Korea Business Visa in 2026 — How Much to Invest, How Long You Can Stay, and Bringing Your Family","url":"korea-business-visa-investment-and-family-guide-2026","disclaimer":"This installment covers how the D-9-4 and D-9-5 visas introduced in Episode 1 are actually applied in practice. The full relocation timeline is addressed in Episode 3, and life after settlement in Episode 4.","series":"Episode 2 · Business Immigration Series","publishedAt":"2026.04.17","updatedAt":"2026.04.23","readingMin":11,"sections":[{"id":"s1","heading":"Investment is assessed not by \"how much\" but by \"how it arrived\"","blocks":[{"type":"p","text":"The minimum investment thresholds are straightforward: <b>300 million KRW or more for D-9-4</b> and <b>100 million KRW or more for D-9-5</b>. The numbers themselves are simple. What actually matters in review, however, is not the <b>size</b> of the funds but <b>how those funds reached Korea</b>."},{"type":"numbered","label":"REQUIREMENT","items":[{"n":1,"title":"Remittance under the applicant's own name","text":"Investment funds must be remitted from the applicant's own overseas account to a Korean account held in the applicant's own name. Funds sent from a third-party account, funds borrowed in Korea, funds brought in through cryptocurrency, and funds routed through remittance or payment apps do not qualify as investment capital. Even when a family member has remitted on the applicant's behalf, the applicant must separately prove that the funds substantively belong to them."},{"n":2,"title":"Clarity of remittance purpose","text":"When remitting to Korea, the purpose declared to the bank must clearly state <b>\"investment.\"</b> If the funds were originally declared as \"living expenses,\" \"travel expenses,\" or \"tuition\" and later redirected to business use, recognition as investment capital becomes problematic."},{"n":3,"title":"Legitimacy of the source of funds","text":"The applicant must be able to document how the funds were accumulated in their home country. Employment income requires proof of employment and pay statements; business income requires operational records and tax filings; inheritance or gift requires the corresponding certificates; asset sales require the sale contract and records of the sale proceeds. <b>Clarity of origin carries more weight in review than absolute size</b> of the investment."}]}]},{"id":"s2","heading":"Part of the 100 million KRW may be domestic funds — a D-9-5 special provision","blocks":[{"type":"p","text":"For D-9-5, <b>up to 50 million KRW of the 100 million KRW investment may consist of funds raised domestically in Korea</b>. The remaining 50 million KRW must still be foreign capital remitted from abroad."},{"type":"p","text":"Funds that typically qualify as domestically raised include savings accumulated during the applicant's studies in Korea — part-time work, teaching assistantships, scholarships, or family remittances that the applicant held in a Korean account while residing on a D-2 (Student) or D-10 (Job-seeking) status. Even in this case, the applicant must still document how the funds were lawfully accumulated."},{"type":"callout","text":"This provision is designed so that <b>those who completed their education in Korea can start their own business here without depending on remittances from home</b>. For applicants who cannot send the full amount from overseas, or who have accumulated savings during their studies in Korea, D-9-5 is substantively more accessible than D-9-4."}]},{"id":"s3","heading":"Where the funds must be spent to be \"recognized as investment\"","blocks":[{"type":"p","text":"Simply holding the remitted funds in a personal account in Korea does not qualify them as investment capital. There must be <b>documented evidence that the funds were actually deployed into the business</b>."},{"type":"table","title":"Recognized Uses vs. Non-Recognized Uses of Investment Funds","headers":["Recognized deployment","Non-recognized deployment"],"rows":[["Franchise fees · lease security deposits","Personal living expenses (housing, food, communications)"],["Interior construction · facilities and equipment","Asset purchases unrelated to the business"],["Initial inventory purchases","Loans to the applicant or family members"],["Consulting and advisory fees · working capital","Payments to entities with no clear business substance"]],"note":"Each item requires a remittance record, contract, tax invoice, and receipt; the source of funds must be traceable back to the applicant's own remittance account."},{"type":"p","text":"This is why our project design begins with a budget allocation plan. Rather than first remitting 300 million KRW or 100 million KRW and then deciding where to spend it, <b>the deployment plan should be designed before relocation, and funds should be moved in accordance with that plan so that investment capital is fully recognized at visa review</b>."}]},{"id":"s4","heading":"How industry classification and licensing are interwoven with the visa","blocks":[{"type":"p","text":"In starting a business in Korea, business registration (for tax purposes) and industry-specific licensing are handled by different authorities. Business registration is processed at the district tax office, while industry-specific licensing is handled by the authority competent for each business type. The business visa review can proceed only after both are complete."},{"type":"p","text":"Consider opening a Korean restaurant, for example. First, the commercial lease must be signed. Next, business registration is filed at the competent tax office. Since food service is involved, a <b>business operation filing (영업 신고)</b> must then be submitted to the district or city office, and before that filing, <b>mandatory food-hygiene training</b> must be completed at the public health center. Verification that the kitchen equipment meets Food Sanitation Act standards, fire safety equipment filing, and confirmation that the building's use classification is compatible with a food service business all proceed in parallel. Only after all of this is completed can the visa application stage begin."},{"type":"p","text":"The number and types of authorities involved depend on the industry. A convenience store requires a separate tobacco retailer designation at the district office; an unmanned photo studio may require a mail-order retail filing; a coffee shop is classified as a refreshment establishment within the food service category. Across industries, the district office, public health center, fire department, small-business support center, and tax office each play their respective roles."},{"type":"callout","text":"The challenge is that these procedures follow a <b>strict temporal order</b>. Business registration cannot proceed without a commercial lease, the operation filing cannot proceed without business registration, and the visa review cannot proceed without the operation filing. A delay at any single step pushes back the entire timeline like falling dominoes. This is why it is practically difficult for an applicant still overseas to coordinate sequentially with multiple Korean authorities — and why <b>an integrated pre-relocation plan is essential</b>."}]},{"id":"s-cta-mid","type":"midCta","blocks":[]},{"id":"s5","heading":"For those already residing in Korea — continuing on a business visa via status change","blocks":[{"type":"p","text":"Everything above assumes a relocation from abroad. But there are also <b>foreign nationals already residing in Korea</b>. Typical cases include those on F-3 (Accompanying Family) as the dependent of a Korean spouse's family, those on E-7 (Specially-designated Activities) employed by a Korean company, and those on D-2 (Student) or D-10 (Job-seeking)."},{"type":"p","text":"Those already in Korea can continue on a business visa through a <b>change of status of stay</b>, without having to return to the home country. Rather than obtaining a new D-9 visa via a Korean diplomatic mission abroad, the application is filed directly with the Immigration Office inside Korea. The home-country documentation burden is significantly lighter, and the entire procedure can be completed in Korea without a break in residency."},{"type":"p","text":"For former international students who meet the D-9-5 requirements, this is the default path. Since both the Korean degree and the residency record are verifiable domestically, an in-country status change is the natural route. Those currently in Korea on employment or accompanying-family status who wish to transition into business can likewise pursue an in-country status change, provided they meet the requirements."}]},{"id":"s6","heading":"Period of stay and extension review","blocks":[{"type":"p","text":"For both D-9-4 and D-9-5, <b>the initial period of stay is typically one year</b>. Continuing to reside in Korea beyond that year requires a period-of-stay extension."},{"type":"p","text":"What is evaluated at extension review is <b>whether the business is actually operating</b>. Specifically, revenue performance, tax filing history, maintenance of the business premises, employment status, and continuity of the commercial lease are all examined. Applicants who only formally satisfied the investment threshold at visa issuance but have no actual business activity will find extension difficult."},{"type":"callout","text":"The implication is clear. In Business Immigration, obtaining the visa is not the finish line — <b>sustaining active business operation is the condition for sustaining residency</b>. This is why our center provides post-settlement legal support as a separate ongoing service, in addition to the initial relocation and launch work. Episode 4 addresses this long-term perspective in detail."}]},{"id":"s7","heading":"Inviting accompanying family — bringing spouse and children on F-3 status","blocks":[{"type":"p","text":"A D-9-4 or D-9-5 holder may <b>invite their spouse and minor children to Korea</b>. The status granted to family members is <b>F-3 (Accompanying Family)</b>."},{"type":"p","text":"The invitation procedure works as follows: the principal applicant first obtains a <b>Certificate for Confirmation of Visa Issuance (CCVI, 사증발급인정서)</b> from the Immigration Office in Korea; family members abroad then use this certificate to apply for an F-3 visa at the competent Korean diplomatic mission. The F-3 period of stay is tied to the principal holder's (D-9 holder's) period of stay. When the principal holder receives an extension, the family's F-3 can be extended together; conversely, if the principal holder's stay ends, the family's F-3 ends as well."},{"type":"p","text":"A key point to note about F-3: <b>employment is restricted as a general rule</b>. If a spouse wishes to pursue separate employment in Korea, a change from F-3 to a work-eligible status must be considered separately. For school-age children, enrollment in Korean public or private schools is available, and special admissions tracks for foreign students are offered for university admission."},{"type":"p","text":"Inviting parents is not feasible on the D-9 holder's status alone; it must be examined separately through a different status (for example, F-1 Visitor/Cohabitant). The scope of family members to be invited and the status design for each is something we review together during the pre-consultation stage."}]},{"id":"closing","heading":"What the next episodes cover","blocks":[{"type":"p","text":"This completes the practical structure of Korea's Business Immigration visa system: how investment funds are recognized, how they should be deployed, how industry classification and licensing interlock with the visa, the change-of-status route for those already in Korea, the extension review, and the accompanying-family invitation structure."},{"type":"p","text":"The next installment turns to the question: <b>given these requirements, how does the actual relocation and launch unfold?</b> From the first pre-consultation from the home country through the day the doors open in Korea — the substance of our five-stage project."},{"type":"numbered","label":"EPISODE","items":[{"n":3,"title":"Episode 3 — The Relocation & Launch Flow","text":"What actually happens when starting a business in Korea — the content of the five-stage project and the common mistakes to avoid"},{"n":4,"title":"Episode 4 — After Business Immigration","text":"Long-term residency, family settlement, real estate, social insurance — the starting point of the long arc that follows visa issuance"}]},{"type":"p","text":"Lawyeon Visa & Immigration Center brings together experienced attorneys from Law Firm Lawyeon, interpreter-coordinators, and startup immigration specialists to support foreign sole-proprietor Business Immigration via D-9-4 and D-9-5. Initial consultations are free of charge, and applicants can submit inquiries directly from their home country through our consultation thread."}]}],"related":[{"tag":"EP 1","title":"How to Start a Business in Korea as a Foreigner — The 2026 Guide","url":"start-a-business-in-korea-as-a-foreigner-2026"},{"tag":"EP 3","title":"How to Open a Store in Korea as a Foreigner — The Step-by-Step 2026 Process","url":"how-to-open-a-store-in-korea-as-a-foreigner-2026"},{"tag":"EP 4","title":"How to Stay in Korea Long-Term as a Foreign Business Owner — Residency, Family, Real Estate, Healthcare (2026)","url":"how-to-stay-in-korea-long-term-as-a-business-owner-2026"}]}$$,
  NOW(),
  NOW()
)
